 {"id":"bd-33w.2.6","title":"Port operational/admin CLI surfaces: update/rollback path and AGENTS blurb commands","description":"Background: operational commands reduce friction for real-world usage and maintenance.\\nWork: implement --update/--check-update/--rollback/--yes plus --agents-add/remove/update/check/dry-run/force semantics.\\nAcceptance: commands are safe, deterministic, and provide clear user-facing remediation messages.\\nTesting/logging: unit tests for command parsing + e2e script coverage for happy/error paths.","status":"open","priority":2,"issue_type":"feature","created_at":"2026-02-27T22:25:56.634965494Z","created_by":"ubuntu","updated_at":"2026-02-27T22:26:00.252523856Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["admin","cli","ops"],"dependencies":[{"issue_id":"bd-33w.2.6","depends_on_id":"bd-33w.2","type":"parent-child","created_at":"2026-02-27T22:25:56.634965494Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.2.6","depends_on_id":"bd-33w.2.1","type":"blocks","created_at":"2026-02-27T22:26:00.252483891Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-33w.3","title":"TUI Visual and Interaction Fidelity Parity","description":"Background: bvr TUI is functional but not yet visually/behaviorally identical to legacy bv.\\nGoal: achieve keyboard workflow and rendering fidelity, including breakpoint-specific layouts and modal behavior.\\nScope: main/board/insights/graph/history views, search flows, update/tutorial/pages modals, and keybinding parity.\\nAcceptance: golden visual snapshots and scripted keyflow tests demonstrate indistinguishable behavior for critical flows.","status":"blocked","priority":1,"issue_type":"epic","created_at":"2026-02-27T22:25:55.251396186Z","created_by":"ubuntu","updated_at":"2026-02-27T22:26:28.656805999Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["parity","tui","ux"],"dependencies":[{"issue_id":"bd-33w.3","depends_on_id":"bd-33w","type":"parent-child","created_at":"2026-02-27T22:25:55.251396186Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3","depends_on_id":"bd-33w.1.2","type":"blocks","created_at":"2026-02-27T22:25:59.474475625Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-33w.3.1","title":"Establish TUI visual token baseline with breakpoint-aware layout parity","description":"Background: visual drift accumulates without explicit tokens and breakpoints.\\nWork: codify typography/spacing/border/status token system and map layouts for narrow/medium/wide terminal widths.\\nAcceptance: deterministic snapshot suite validates structure and key textual affordances at each breakpoint.\\nTesting/logging: include screenshot/vhs artifacts and a concise diff report on failures.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-27T22:25:56.716391897Z","created_by":"ubuntu","updated_at":"2026-02-27T22:26:30.062726610Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["layout","tui","visual"],"dependencies":[{"issue_id":"bd-33w.3.1","depends_on_id":"bd-33w.1.1","type":"blocks","created_at":"2026-02-27T22:26:29.401895430Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3.1","depends_on_id":"bd-33w.1.2","type":"blocks","created_at":"2026-02-27T22:26:30.062685634Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3.1","depends_on_id":"bd-33w.1.3","type":"blocks","created_at":"2026-02-27T22:26:29.492857482Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3.1","depends_on_id":"bd-33w.3","type":"parent-child","created_at":"2026-02-27T22:25:56.716391897Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
