 {"id":"bd-33w.3.5","title":"Build TUI parity regression harness (unit + snapshots + keyflow e2e with logs)","description":"Background: TUI regressions are frequent without visual/interaction automation.\\nWork: add comprehensive tests covering state transitions, rendering snapshots, and end-to-end keyboard journeys with reproducible fixtures.\\nAcceptance: CI catches visual and behavior regressions with actionable diff artifacts.\\nTesting/logging: store per-run logs, snapshots, and replay scripts for triage.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-27T22:25:57.060610212Z","created_by":"ubuntu","updated_at":"2026-02-27T22:27:26.659996546Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["e2e","testing","tui"],"dependencies":[{"issue_id":"bd-33w.3.5","depends_on_id":"bd-33w.3","type":"parent-child","created_at":"2026-02-27T22:25:57.060610212Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3.5","depends_on_id":"bd-33w.3.2","type":"blocks","created_at":"2026-02-27T22:26:00.804618467Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3.5","depends_on_id":"bd-33w.3.3","type":"blocks","created_at":"2026-02-27T22:26:00.889830194Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3.5","depends_on_id":"bd-33w.3.4","type":"blocks","created_at":"2026-02-27T22:26:00.996365409Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3.5","depends_on_id":"bd-33w.3.6","type":"blocks","created_at":"2026-02-27T22:27:26.659949327Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-33w.3.6","title":"Implement debug-render parity flags for deterministic TUI diagnostics","description":"Background: legacy exposes --debug-render/--debug-width/--debug-height for non-interactive TUI diagnostics.\\nWork: port deterministic view rendering hooks and dimensions controls so CI and humans can capture faithful debug artifacts.\\nAcceptance: debug output is stable, useful for failure triage, and aligned with legacy semantics.\\nTesting/logging: add unit + e2e coverage ensuring debug renders include key state markers and width/height handling.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-27T22:27:26.187373675Z","created_by":"ubuntu","updated_at":"2026-02-27T22:27:26.561950739Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["debug","diagnostics","tui"],"dependencies":[{"issue_id":"bd-33w.3.6","depends_on_id":"bd-33w.1.1","type":"blocks","created_at":"2026-02-27T22:27:26.290518928Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3.6","depends_on_id":"bd-33w.1.2","type":"blocks","created_at":"2026-02-27T22:27:26.381609841Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3.6","depends_on_id":"bd-33w.1.3","type":"blocks","created_at":"2026-02-27T22:27:26.472073930Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3.6","depends_on_id":"bd-33w.3","type":"parent-child","created_at":"2026-02-27T22:27:26.187373675Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.3.6","depends_on_id":"bd-33w.3.2","type":"blocks","created_at":"2026-02-27T22:27:26.561911676Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-33w.4","title":"Workspace, Hooks, Export, and Pages Integration Parity","description":"Background: legacy bv includes multi-repo workspace aggregation and export pipelines that are central to user workflows.\\nGoal: restore full ecosystem parity beyond core graph analysis.\\nScope: workspace/repo filtering, hook lifecycle, markdown export, graph export, static pages pipeline, and brief bundles.\\nAcceptance: integration commands produce expected outputs and are exercised by e2e scripts with detailed logs.","status":"blocked","priority":1,"issue_type":"epic","created_at":"2026-02-27T22:25:55.394084187Z","created_by":"ubuntu","updated_at":"2026-02-27T22:26:28.748089243Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["integrations","parity","workflow"],"dependencies":[{"issue_id":"bd-33w.4","depends_on_id":"bd-33w","type":"parent-child","created_at":"2026-02-27T22:25:55.394084187Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-33w.4","depends_on_id":"bd-33w.1.1","type":"blocks","created_at":"2026-02-27T22:25:59.553966561Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
